	('14eb704f-5584-4dfe-835d-d468ff787097', 'c5d30a55-8d9a-46e6-b8d0-6accc0415c1c', 'Accountability in the Workplace', '49254f45-f58d-4ab8-a655-bb4e1de68833', 'Intermediate', 15, '[{"id": 1, "type": "mcq", "options": ["Responsibility", "Ownership", "Autonomy", "Transparency"], "question": "Which of the following is NOT a key principle of accountability in the workplace?", "skill_tag": "Accountability principles", "difficulty": "easy", "correct_answer": "Autonomy", "estimated_time": 45}, {"id": 2, "type": "mcq", "options": ["Reduced employee turnover", "Increased productivity", "Improved customer satisfaction", "Better decision-making"], "question": "What is the primary benefit of fostering a culture of accountability in the workplace?", "skill_tag": "Benefits of accountability", "difficulty": "easy", "correct_answer": "Increased productivity", "estimated_time": 50}, {"id": 3, "type": "mcq", "options": ["Providing clear expectations and deadlines", "Micromanaging their daily tasks", "Avoiding feedback on their performance", "Rewarding good work only"], "question": "Which of the following is an effective way to hold employees accountable for their work?", "skill_tag": "Accountability practices", "difficulty": "easy", "correct_answer": "Providing clear expectations and deadlines", "estimated_time": 55}, {"id": 4, "type": "mcq", "options": ["To motivate employees", "To measure performance", "To increase job satisfaction", "To improve work-life balance"], "question": "What is the primary purpose of setting SMART goals in the workplace?", "skill_tag": "SMART goals", "difficulty": "easy", "correct_answer": "To measure performance", "estimated_time": 45}, {"id": 5, "type": "mcq", "options": ["Blame-shifting", "Siloed decision-making", "Lack of feedback", "Continuous improvement"], "question": "Which of the following is a key characteristic of a culture of accountability?", "skill_tag": "Accountability culture", "difficulty": "easy", "correct_answer": "Continuous improvement", "estimated_time": 50}, {"id": 6, "type": "mcq", "options": ["Provide constructive feedback and set clear expectations", "Reassign the employee''s tasks to other team members", "Terminate the employee''s employment", "Publicly reprimand the employee"], "question": "An employee consistently misses deadlines and delivers subpar work. What is the BEST way for a manager to address this issue?", "skill_tag": "Accountability management", "difficulty": "medium", "correct_answer": "Provide constructive feedback and set clear expectations", "estimated_time": 80}, {"id": 7, "type": "mcq", "options": ["Hold a team meeting to discuss the issue", "Redistribute the work among other team members", "Confront the team member and demand an explanation", "Schedule a one-on-one meeting to understand the root cause"], "question": "A team member fails to complete their assigned tasks, causing a delay in a critical project. How should the team leader address this issue?", "skill_tag": "Accountability problem-solving", "difficulty": "medium", "correct_answer": "Schedule a one-on-one meeting to understand the root cause", "estimated_time": 75}, {"id": 8, "type": "mcq", "options": ["Encourage employees to work independently", "Reduce communication and feedback", "Increase monitoring of employee activities", "Implement regular check-ins and progress updates"], "question": "Which of the following is an effective way to foster a culture of accountability in a remote work environment?", "skill_tag": "Accountability in remote work", "difficulty": "medium", "correct_answer": "Implement regular check-ins and progress updates", "estimated_time": 85}, {"id": 9, "type": "mcq", "options": ["Provide additional training on accountability", "Assign the team member to a different project", "Publicly call out the team member''s behavior", "Terminate the team member''s employment"], "question": "A team member consistently fails to take responsibility for their mistakes. What is the BEST way for a manager to 