	('568e6e7d-c68f-4ce6-9f27-dd2e0b2ec825', 'c5d30a55-8d9a-46e6-b8d0-6accc0415c1c', 'Appreciative Inquiry: Positive Organizational Change', '3743ff84-df41-40ec-a704-c2204a8ae159', 'Intermediate', 15, '[{"id": 1, "type": "mcq", "options": ["To identify and solve problems", "To focus on strengths and opportunities", "To implement major organizational changes", "To critique current organizational processes"], "question": "What is the primary goal of Appreciative Inquiry?", "skill_tag": "Appreciative Inquiry: Positive Organizational Change Fundamentals", "difficulty": "easy", "correct_answer": "To focus on strengths and opportunities", "estimated_time": 45}, {"id": 2, "type": "mcq", "options": ["Autocratic decision-making", "Constructionist view", "Deficit-based thinking", "Continuous improvement"], "question": "Which of the following is a key principle of Appreciative Inquiry?", "skill_tag": "Appreciative Inquiry: Positive Organizational Change Fundamentals", "difficulty": "easy", "correct_answer": "Constructionist view", "estimated_time": 50}, {"id": 3, "type": "mcq", "options": ["Dream", "Deliver", "Design", "Discover"], "question": "What is the first stage of the Appreciative Inquiry 4-D Cycle?", "skill_tag": "Appreciative Inquiry: Positive Organizational Change Fundamentals", "difficulty": "easy", "correct_answer": "Discover", "estimated_time": 40}, {"id": 4, "type": "mcq", "options": ["Strength-based", "Generative", "Deficit-based", "Collaborative"], "question": "Which of the following is NOT a key characteristic of Appreciative Inquiry?", "skill_tag": "Appreciative Inquiry: Positive Organizational Change Fundamentals", "difficulty": "easy", "correct_answer": "Deficit-based", "estimated_time": 45}, {"id": 5, "type": "mcq", "options": ["To develop an implementation plan", "To identify areas for improvement", "To analyze current processes", "To envision a preferred future"], "question": "What is the purpose of the ''Dream'' stage in the Appreciative Inquiry 4-D Cycle?